import ast, subprocess, sys

WT = "/home/polaris/wt/phase3ab4"
files = subprocess.check_output(
    ["git", "-C", WT, "diff", "--name-only", "HEAD"], text=True
).split()
files = [f for f in files if f.endswith(".py")]

def strip_docstrings(tree):
    for node in ast.walk(tree):
        if isinstance(node, (ast.Module, ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
            body = node.body
            if body and isinstance(body[0], ast.Expr) and isinstance(getattr(body[0], "value", None), ast.Constant) and isinstance(body[0].value.value, str):
                node.body = body[1:]
    return tree

def norm(src):
    tree = ast.parse(src)
    tree = strip_docstrings(tree)
    return ast.dump(tree)

failures = []
for f in files:
    try:
        head_src = subprocess.check_output(["git", "-C", WT, "show", f"HEAD:{f}"], text=True)
    except subprocess.CalledProcessError:
        failures.append(f"{f}: not in HEAD")
        continue
    with open(f"{WT}/{f}") as fh:
        wt_src = fh.read()
    try:
        if norm(head_src) != norm(wt_src):
            failures.append(f"{f}: AST differs")
    except SyntaxError as e:
        failures.append(f"{f}: syntax error {e}")

print("FILES:", len(files))
if failures:
    for x in failures:
        print("FAIL:", x)
else:
    print("ALL PASS")
